import React, { useState } from 'react';
import {
  CModal, CModalHeader, CModalTitle, CModalBody, CModalFooter,
  CButton, CFormSelect,
} from '@coreui/react-pro';
import { settingsUserAdmins } from 'src/services/SupperSettings';
import { useDispatch } from 'react-redux';
import { setSelectedUser } from 'src/store/userSlected/index';
import PropTypes from 'prop-types';
import i18n   from 'src/i18n';
const SelectAdminModal = ({ refresh }) => {
  const [visible, setVisible] = useState(false);
  const [selectedAdmin, setSelectedAdmin] = useState('');
  const [adminList, setAdminList] = useState([]);
  const dispatch = useDispatch();

  const handleOpen = () => {
    setVisible(true);
    fetchUserAdmins();
  };

  const handleClose = () => {
    setVisible(false);
    setSelectedAdmin('');
  };

  const handleSave = () => {
    const selectedData = adminList.find((admin) => admin.id === selectedAdmin);
    if (selectedData) {
      dispatch(setSelectedUser(selectedData));
      console.log("Dispatched selected user:", selectedData);
      if (typeof refresh === 'function') {
        refresh();
      }
    }
    handleClose();
  };

  const fetchUserAdmins = async () => {
    try {
      const res = await settingsUserAdmins.getUsersAdmin();
      if (res?.data) setAdminList(res.data);
    } catch (err) {
      console.error('Erreur chargement admins :', err);
    }
  };

  return (
    <>
      <CButton color="primary" onClick={handleOpen}>
        {i18n.t('selectAdminButton')} {/* ✅ Bouton d'ouverture */}
      </CButton>

      <CModal visible={visible} onClose={handleClose}>
        <CModalHeader>
          <CModalTitle>{i18n.t('selectUserTitle')}</CModalTitle>
        </CModalHeader>
        <CModalBody>
          <CFormSelect
            value={selectedAdmin}
            onChange={(e) => setSelectedAdmin(e.target.value)}
          >
            <option value="">{i18n.t('chooseUserPlaceholder')}</option>
            {adminList.map((admin) => (
              <option key={admin.id} value={admin.id}>
                {admin.username} ({admin.email})
              </option>
            ))}
          </CFormSelect>
        </CModalBody>
        <CModalFooter>
          <CButton color="secondary" onClick={handleClose}>
            {i18n.t('cancel')}
          </CButton>
          <CButton color="primary" onClick={handleSave} disabled={!selectedAdmin}>
            {i18n.t('saveButton')}
          </CButton>
        </CModalFooter>
      </CModal>
    </>
  );
};

SelectAdminModal.propTypes = {
  refresh: PropTypes.func,
};

export default SelectAdminModal;
