import React, { useState, useRef } from 'react'
import FullCalendar from '@fullcalendar/react'
import dayGridPlugin from '@fullcalendar/daygrid'
import timeGridPlugin from '@fullcalendar/timegrid'
import interactionPlugin from '@fullcalendar/interaction'
import {
  CCard,
  CCardBody,
  CCardHeader,
  CRow,
  CCol,
  CFormInput,
  CButton
} from '@coreui/react-pro'
import AppointmentsC from '../../appointments/Appointments'
import UnavailabilitiesC from '../../unavailabilities/Unavailabilities'
import AddEventModal from './AddAppointements'
import AppointmentsView from '../../appointments/Appointments.view'
import { settingsAppointments, settingsUnavailabilities } from 'src/services/standardUsers'
import frLocale from '@fullcalendar/core/locales/fr'
import i18n from 'src/i18n'
import './style.css'
import { cilLoop, cilOpentype } from '@coreui/icons'
import CIcon from '@coreui/icons-react'
import { Link } from 'react-router-dom'
import ModalUserSelect from './Select.User'
import { useSelector } from 'react-redux';
const UserCalendarPlugin = () => {
  const [weekendsVisible] = useState(true)
  const [currentEvents, setCurrentEvents] = useState([])
  const [viewDates, setViewDates] = useState({ start: null, end: null })
  const [selectedDate, setSelectedDate] = useState('')
  const [showModal, setShowModal] = useState(false)
  const selectedUser = useSelector((state) => state.selectedUser.selectedUser);
  const [newEventInfo, setNewEventInfo] = useState({
    title: '',
    startStr: '',
    endStr: '',
    allDay: false,
    calendar: null,
  })
  const [List, setList] = useState([])
  const [ListUnivailbe, setListUnivailbe] = useState([])

  const calendarRef = useRef(null)

  const fetchUnavailabilities = async () => {
    try {
      const list = await settingsUnavailabilities.getunavailabilities()
      if (list) {
        const allActiveDays = list.data.flatMap(item => item.activeDays || [])
        setListUnivailbe(allActiveDays)
      }
    } catch (error) {
      console.error('Error fetching unavailabilities:', error)
    }
  }

  const fetchAppointments = async (data) => {
    try {
      fetchUnavailabilities()
      const list = await settingsAppointments.getAppointmentsFilter(data)
      if (list && list.data) {
        setList(list.data)
        console.log("liste hher", list)
      }
    } catch (error) {
      console.error('Error fetching appointments:', error)
    }
  }

  const handleDateSelect = (selectInfo) => {
    setNewEventInfo({
      title: '',
      startStr: selectInfo.startStr,
      endStr: selectInfo.endStr,
      allDay: selectInfo.allDay,
      calendar: selectInfo.view.calendar,
    })
    selectInfo.view.calendar.unselect()
    setShowModal(true)
  }

  const handleEventClick = (clickInfo) => {
    console.log('Event clicked:', clickInfo.event)
  }

  const handleEvents = (events) => {
    setCurrentEvents(events)
  }

  const handleSaveEvent = () => {
    if (newEventInfo.title && newEventInfo.calendar) {
      newEventInfo.calendar.addEvent({
        id: 'createEventId',
        title: newEventInfo.title,
        start: newEventInfo.startStr,
        end: newEventInfo.endStr,
        allDay: newEventInfo.allDay,
      })
    }
    setShowModal(false)
    setNewEventInfo({
      title: '',
      startStr: '',
      endStr: '',
      allDay: false,
      calendar: null,
    })
  }

  const handleDatesSet = (arg) => {
    setViewDates({
      start: arg.startStr,
      end: arg.endStr,
    })
    fetchAppointments({
      start: arg.startStr,
      end: arg.endStr,
    })
  }

  const renderEventContent = (eventInfo) => (
    <div>
      <AppointmentsView
        selectedAppointments={eventInfo}
        refresh={() => fetchAppointments(viewDates)}
      />
    </div>
  )

  const handleCustomDateSelect = () => {
    if (!selectedDate) return

    const start = new Date(selectedDate)
    const end = new Date(start)
    end.setDate(end.getDate() + 6) // 1 week range

    const range = {
      startStr: start.toISOString().split('T')[0],
      endStr: end.toISOString().split('T')[0],
    }

    const calendarApi = calendarRef.current?.getApi()
    if (calendarApi) {
      calendarApi.gotoDate(start)
    }

    handleDatesSet(range)
  }

  return (
    <CCard className="mb-4">
      <CCardHeader>
        <CRow className="align-items-center">
          <CCol md="6" xs="12">
            <div className="d-flex align-items-center gap-2">
              <CFormInput
                type="date"
                value={selectedDate}
                onChange={(e) => setSelectedDate(e.target.value)}
              />
              <CButton color="primary" onClick={handleCustomDateSelect}>
                <CIcon icon={cilLoop} />
              </CButton>
            </div>
          </CCol>
          <CCol md="6" xs="12" className="text-md-end mt-md-0 mt-3">
            <div className="d-flex justify-content-end gap-2 flex-wrap">
              <Link to="/standard/settings/calendars" className="btn btn-secondary d-inline-flex align-items-center">
                <CIcon icon={cilOpentype} className="me-1" />
                {i18n.t('mycalendar')}
              </Link>
              <ModalUserSelect refresh={() => fetchAppointments(viewDates)} />
              <AppointmentsC refresh={() => fetchAppointments(viewDates)} />
            </div>
          </CCol>
        </CRow>
      </CCardHeader>

      <CCardBody>
        <div className="custom-calendar">
          <FullCalendar
            ref={calendarRef}
            plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin]}
            headerToolbar={{
              left: 'prev,next today',
              center: 'title',
              right: 'dayGridMonth,timeGridWeek,timeGridDay',
            }}
            initialView="dayGridMonth"
            editable={true}
            selectable={true}
            selectMirror={true}
            dayMaxEvents={true}
            weekends={weekendsVisible}
            select={handleDateSelect}
            eventContent={renderEventContent}
            eventClick={handleEventClick}
            eventsSet={handleEvents}
            datesSet={handleDatesSet}
            events={[...List, ...ListUnivailbe]}
            locale={frLocale}
            firstDay={1}
            height="600px"
            allDaySlot={false}
            slotMinTime="08:00:00"
            slotMaxTime="18:00:00"
          />
        </div>
      </CCardBody>
    </CCard>
  )
}

export default UserCalendarPlugin
